import React from 'react';
import styles from './confirmation-order.module.css';
import Title from '../../../title';

const ConfirmationOrder = () => {
  return (
    <div className={styles.confirmation__order}>
        <img src="/images/CheckCircle.svg" width={100} height={100} alt="confirmation" />
        <Title level="h3" className={styles.confirmation__order_title}>Payment Confirmed</Title>
        <span className={styles.order_no}>ORDER #2039</span>
        <p className={styles.thanks}> Thank you Joe for buying Candleaf. The nature is grateful to you. Now that your order is confirmed it will be ready to ship in 2 days. Please check your inbox in the future for your order updates.</p>

    </div>
  )
}

export default ConfirmationOrder;
